    int value;
} record;

typedef struct {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    int is_leaf;
    int num_keys;
} knode;

kernel void findK(
    long maxheight,
    const global knode *knodes,
    long knodes_elem,
    const global record *records,
    global long *currKnode,
    global long *offset,
    global int *keys,
    global record *ans)
{
    int bid = get_global_id(0) / get_local_size(0);
    int thid = get_global_id(0) % get_local_size(0);
    int count = get_global_size(0) / get_local_size(0);

    if (bid >= count) return;

    int threadsPerBlock = get_local_size(0);
    long current_knode_idx = currKnode[bid];
    long offset_val = offset[bid];
    int key_val = keys[bid];

    for (long i = 0; i < maxheight; i++) {
        if (thid < threadsPerBlock) {
            if ((knodes[current_knode_idx].keys[thid] <= key_val) && 
                (knodes[current_knode_idx].keys[thid + 1] > key_val)) {
                if (knodes[offset_val].indices[thid] < knodes_elem) {
                    offset_val = knodes[offset_val].indices[thid];
                }
            }
        }
        if (thid == 0) {
            current_knode_idx = offset_val;
        }
    }

    if (thid < threadsPerBlock) {
        if (knodes[current_knode_idx].keys[thid] == key_val) {
            ans[bid].value = records[knodes[current_knode_idx].indices[thid]].value;
        }
    }
}

